async (page) => {
  // Grinding loop: 5 iterations
  for (let i = 0; i < 5; i++) {
    const entities = await page.evaluate(() => window.__latestAsciiMap?.entities || []);

    // Loot drops
    for (const e of entities.filter(e => e.type === 4)) {
      if (e.on_screen) { await page.evaluate((l) => window.__clickEntity(l), e.label); await page.waitForTimeout(300); }
    }

    // Attack nearest on-screen rat
    const rat = entities.find(e => e.name === 'Rat' && e.on_screen);
    if (rat) {
      await page.evaluate((l) => window.__clickEntity(l), rat.label);
      await page.waitForTimeout(9000);
    } else {
      // Walk around to find rats
      await page.evaluate(({x,y}) => window.__clickTile(x,y), {x: 175, y: 120});
      await page.waitForTimeout(3000);
    }
  }

  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return { level: gs.player_stats.level, hp: gs.player_stats.hp + '/' + gs.player_stats.max_hp, pos: gs.player_position, inventory: gs.inventory };
  });
  return JSON.stringify(state);
}

async (page) => {
  // Walk to Bike Lyson achievement NPC at (166, 114)
  const r = await page.evaluate(({x,y}) => JSON.stringify(window.__clickTile(x,y)), {x: 166, y: 115});
  await page.waitForTimeout(4000);

  const pos = await page.evaluate(() => window.__latestGameState.player_position);
  const entities = await page.evaluate(() => window.__latestAsciiMap?.entities || []);
  const bikeLyson = entities.find(e => e.name === 'Bike Lyson');

  return JSON.stringify({ walked: r, pos, bikeLysonLabel: bikeLyson?.label, dist: bikeLyson?.distance });
}

