async (page) => {
  // Navigate back to rat area and grind
  await page.evaluate(({x,y}) => window.__clickTile(x,y), {x: 175, y: 120});
  await page.waitForTimeout(3000);

  // 5-round grinding loop
  for (let i = 0; i < 5; i++) {
    const entities = await page.evaluate(() => window.__latestAsciiMap?.entities || []);

    // Loot drops
    for (const e of entities.filter(e => e.type === 4 && e.on_screen)) {
      await page.evaluate((l) => window.__clickEntity(l), e.label); await page.waitForTimeout(300);
    }

    // Attack nearest rat
    const rat = entities.find(e => e.name === 'Rat' && e.on_screen);
    if (rat) {
      await page.evaluate((l) => window.__clickEntity(l), rat.label);
      await page.waitForTimeout(9000);
    } else {
      // Wander to find rats
      const dirs = [{x:178,y:120},{x:172,y:119},{x:175,y:126},{x:169,y:121}];
      const d = dirs[i % dirs.length];
      await page.evaluate(({x,y}) => window.__clickTile(x,y), d);
      await page.waitForTimeout(2500);
    }
  }

  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return { level: gs.player_stats.level, hp: gs.player_stats.hp + '/' + gs.player_stats.max_hp, pos: gs.player_position };
  });
  return JSON.stringify(state);
}

async (page) => {
  // Warp to Mudwich
  await page.evaluate(() => {
    window.game.menu.warp.show();
    setTimeout(() => document.getElementById('warp0').click(), 500);
  });
  await page.waitForTimeout(4000);

  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const gs = JSON.parse(state);
  return JSON.stringify({ pos: gs.player_position, level: gs.player_stats.level, hp: gs.player_stats.hp + '/' + gs.player_stats.max_hp, inventory: gs.inventory });
}
